INSERT INTO "Recipes"
    ("Id", "DietitianId", "Name", "Slug", "Description", "IsPublic", "IsDemo", "IsDraft", "IsHiddenFromProduction", "StepsJson")
VALUES
    ('a1000001-0000-0000-0000-000000000001', 'dd000001-0000-0000-0000-000000000000', 'Domatesli Tam Bugday Makarna', 'domatesli-tam-bugday-makarna-r01', 'Clinic pasta with tomato, olive oil and light seasoning.', FALSE, FALSE, FALSE, FALSE, '["Boil the pasta until tender.","Saute tomato and garlic with olive oil.","Combine and finish with herbs."]'),
    ('a1000002-0000-0000-0000-000000000002', 'dd000001-0000-0000-0000-000000000000', 'Izgara Tavuklu Salata', 'izgara-tavuklu-salata-r02', 'High protein salad with grilled chicken breast and fresh vegetables.', FALSE, FALSE, FALSE, FALSE, '["Grill the chicken breast.","Chop the vegetables and greens.","Serve with olive oil and lemon."]'),
    ('a1000003-0000-0000-0000-000000000003', 'dd000001-0000-0000-0000-000000000000', 'Kirmizi Mercimek Corbasi', 'kirmizi-mercimek-corbasi-r03', 'Balanced clinic soup with red lentils, carrot and onion.', FALSE, FALSE, FALSE, FALSE, '["Saute onion and carrot.","Add lentils and water.","Simmer until soft and blend."]'),
    ('a1000004-0000-0000-0000-000000000004', 'dd000001-0000-0000-0000-000000000000', 'Yogurtlu Bulgur Salatasi', 'yogurtlu-bulgur-salatasi-r04', 'Refreshing bulgur salad with yogurt, herbs and lemon.', FALSE, FALSE, FALSE, FALSE, '["Cook the bulgur and cool it down.","Mix yogurt with lemon and herbs.","Fold everything together and chill."]'),
    ('a1000005-0000-0000-0000-000000000005', 'dd000001-0000-0000-0000-000000000000', 'Ispanakli Yumurta', 'ispanakli-yumurta-r05', 'Protein rich breakfast with spinach, onion and eggs.', FALSE, FALSE, FALSE, FALSE, '["Saute onion and spinach.","Add beaten eggs.","Cook gently until set."]'),
    ('a1000006-0000-0000-0000-000000000006', 'dd000001-0000-0000-0000-000000000000', 'Zeytinyagli Patlican', 'zeytinyagli-patlican-r06', 'Mediterranean eggplant dish with tomato and onion.', FALSE, FALSE, FALSE, FALSE, '["Saute onion and garlic in olive oil.","Add diced eggplant and tomato.","Cook until vegetables are tender."]'),
    ('a1000007-0000-0000-0000-000000000007', 'dd000001-0000-0000-0000-000000000000', 'Ton Balikli Salata', 'ton-balikli-salata-r07', 'Light salad with tuna, greens and fresh vegetables.', FALSE, FALSE, FALSE, FALSE, '["Drain the tuna well.","Combine with chopped vegetables and greens.","Dress with olive oil and lemon."]'),
    ('a1000008-0000-0000-0000-000000000008', 'dd000001-0000-0000-0000-000000000000', 'Nohutlu Ispanak', 'nohutlu-ispanak-r08', 'Fiber and protein focused meal with spinach, chickpeas and olive oil.', FALSE, FALSE, FALSE, FALSE, '["Saute onion and garlic.","Add chickpeas and spinach.","Cook briefly until the spinach softens."]'),
    ('a1000009-0000-0000-0000-000000000009', 'dd000001-0000-0000-0000-000000000000', 'Firin Somon', 'firin-somon-r09', 'Omega rich baked salmon with lemon and herbs.', FALSE, FALSE, FALSE, FALSE, '["Place salmon on a tray.","Season with lemon and olive oil.","Bake until just cooked through."]'),
    ('a100000a-0000-0000-0000-00000000000a', 'dd000001-0000-0000-0000-000000000000', 'Avokadolu Tam Bugday Tost', 'avokadolu-tam-bugday-tost-r10', 'Quick breakfast toast with avocado and whole bread.', FALSE, FALSE, FALSE, FALSE, '["Toast the bread.","Mash avocado with seasoning.","Spread and finish with optional cheese."]'),
    ('a100000b-0000-0000-0000-00000000000b', NULL, 'Domates Soslu Makarna', 'domates-soslu-makarna-r11', 'Public recipe with pasta, tomato, garlic and olive oil.', TRUE, FALSE, FALSE, FALSE, '["Boil the pasta.","Cook tomato and garlic sauce.","Mix and serve warm."]'),
    ('a100000c-0000-0000-0000-00000000000c', NULL, 'Mercimek Corbasi', 'mercimek-corbasi-r12', 'Public lentil soup with onion and carrot.', TRUE, FALSE, FALSE, FALSE, '["Saute onion.","Add lentils and carrot.","Cook until soft and blend."]'),
    ('a100000d-0000-0000-0000-00000000000d', NULL, 'Cacik', 'cacik-r13', 'Public yogurt dip with cucumber, mint and garlic.', TRUE, FALSE, FALSE, FALSE, '["Grate the cucumber.","Mix with yogurt and garlic.","Finish with mint and chill."]'),
    ('a100000e-0000-0000-0000-00000000000e', NULL, 'Haslama Tavuk', 'haslama-tavuk-r14', 'Simple boiled chicken meal with onion and carrot.', TRUE, FALSE, FALSE, FALSE, '["Place chicken in a pot with water.","Add onion and carrot.","Simmer until cooked through."]'),
    ('a100000f-0000-0000-0000-00000000000f', NULL, 'Ispanak Salatasi', 'ispanak-salatasi-r15', 'Public spinach salad with lemon and olive oil.', TRUE, FALSE, FALSE, FALSE, '["Wash the spinach thoroughly.","Dress with lemon and olive oil.","Serve immediately."]'),
    ('a1000010-0000-0000-0000-000000000010', NULL, 'Sade Pirinc Pilavi', 'sade-pirinc-pilavi-r16', 'Public rice side dish with butter and seasoning.', TRUE, FALSE, FALSE, FALSE, '["Rinse the rice.","Cook gently with butter and water.","Rest before serving."]'),
    ('a1000011-0000-0000-0000-000000000011', NULL, 'Nohutlu Pilav', 'nohutlu-pilav-r17', 'Public rice dish with chickpeas and onion.', TRUE, FALSE, FALSE, FALSE, '["Saute onion.","Add rice and chickpeas.","Cook until the liquid is absorbed."]'),
    ('a1000012-0000-0000-0000-000000000012', NULL, 'Kiymali Domates', 'kiymali-domates-r18', 'Quick tomato dish with ground meat, onion and spices.', TRUE, FALSE, FALSE, FALSE, '["Saute onion and ground meat.","Add chopped tomato and garlic.","Cook until the sauce thickens."]'),
    ('a1000013-0000-0000-0000-000000000013', NULL, 'Meyveli Yulaf Ezmesi', 'meyveli-yulaf-ezmesi-r19', 'Public breakfast bowl with oats, milk, banana and fruit.', TRUE, FALSE, FALSE, FALSE, '["Cook oats in milk.","Top with banana and fruit.","Finish with a little honey."]'),
    ('a1000014-0000-0000-0000-000000000014', NULL, 'Patlican Yemegi', 'patlican-yemegi-r20', 'Public vegetable dish with eggplant, pepper, onion and tomato.', TRUE, FALSE, FALSE, FALSE, '["Saute onion and pepper.","Add eggplant and tomato.","Cook until the vegetables soften."]')
ON CONFLICT ("Id") DO UPDATE
SET
    "DietitianId" = EXCLUDED."DietitianId",
    "Name" = EXCLUDED."Name",
    "Slug" = EXCLUDED."Slug",
    "Description" = EXCLUDED."Description",
    "IsPublic" = EXCLUDED."IsPublic",
    "IsDemo" = EXCLUDED."IsDemo",
    "IsDraft" = EXCLUDED."IsDraft",
    "IsHiddenFromProduction" = EXCLUDED."IsHiddenFromProduction",
    "StepsJson" = EXCLUDED."StepsJson";

