INSERT INTO "RecipeIngredients" ("Id", "RecipeId", "IngredientId", "Role", "Quantity", "Unit", "CreatedAtUtc")
SELECT
    (
        substr(md5(recipe_id::text || ':' || ingredient_id::text || ':' || role), 1, 8) || '-' ||
        substr(md5(recipe_id::text || ':' || ingredient_id::text || ':' || role), 9, 4) || '-' ||
        substr(md5(recipe_id::text || ':' || ingredient_id::text || ':' || role), 13, 4) || '-' ||
        substr(md5(recipe_id::text || ':' || ingredient_id::text || ':' || role), 17, 4) || '-' ||
        substr(md5(recipe_id::text || ':' || ingredient_id::text || ':' || role), 21, 12)
    )::uuid,
    recipe_id,
    ingredient_id,
    role,
    NULL,
    NULL,
    TIMESTAMPTZ '2026-04-10 09:00:00+00'
FROM recipe_ingredients;

